import { BarRenderer } from '../bar/bar-parser';
import { setBulletBuilderConfig } from './bullet-builder-config';
import { bullet_encode_collectors } from './bullet-encode-helpers';

export class BulletRenderer extends BarRenderer {
    collectEncode() {
        setBulletBuilderConfig.call(this);
        bullet_encode_collectors.call(this);
    }
    getAllowedMarkOperator() {
        return ['levelmarker', 'bar', 'targetmarker'];
    }
}
